+        let modes: &[&str] = if case.mode.eq_ignore_ascii_case("both") {
+            &["strict", "hardened"]
+        } else {
+            &[case.mode.as_str()]
+        };
+
+        for mode in modes {
+            let result = execute_case_via_harness(&case.function, &case.inputs, mode)
+                .unwrap_or_else(|err| {
+                    panic!(
+                        "termios_ops case {} ({mode}) failed to execute via harness: {err}",
+                        case.name
+                    )
+                });
+            assert!(
+                result.host_parity,
+                "termios_ops case {} ({mode}) lost host parity via harness: host_output={}, impl_output={}",
+                case.name, result.host_output, result.impl_output
+            );
+            assert_eq!(
+                result.impl_output, expected_output,
+                "termios_ops case {} ({mode}) mismatched fixture output via harness",
+                case.name
+            );
+        }
+    }
